    ```java
import java.util.*;

public int[] kWeakestRows(int[][] mat, int k) {
    int m = mat.length;
    int[] result = new int[k];
    PriorityQueue<int[]> pq = new PriorityQueue<>((a, b) -> a[0] == b[0] ? a[1] - b[1] : a[0] - b[0]);

    for (int i = 0; i < m; ++i) {
        int soldiers = 0;
        for (int val : mat[i]) {
            if (val == 1) {
                soldiers++;
            } else {
                break;
            }
        }
        pq.add(new int[]{soldiers, i});
    }

    for (int i = 0; i < k; ++i) {
        result[i] = pq.poll()[1];
    }
    return result;
}
```


